mapper.select:
SELECT T.TRADE_ID AS TRADEID, T.SYMBOL AS SYMBOL, T.BUY_ORDER_ID AS BUYORDERID, T.SELL_ORDER_ID AS SELLORDERID, T.PRICE AS PRICE, T.QTY AS QTY, T.CREATED_AT AS EXECUTEDAT, U_TRADES.SIDE AS SIDE FROM ( SELECT TR.TRADE_ID, TR.SYMBOL, TR.BUY_ORDER_ID, TR.SELL_ORDER_ID, TR.PRICE, TR.QTY, TR.CREATED_AT, 'BUY' AS SIDE FROM TRADES TR JOIN ORDERS O_BUY ON TR.BUY_ORDER_ID = O_BUY.ORDER_ID WHERE O_BUY.USER_ID = #{userId}
UNION ALL
SELECT TR.TRADE_ID, TR.SYMBOL, TR.BUY_ORDER_ID, TR.SELL_ORDER_ID, TR.PRICE, TR.QTY, TR.CREATED_AT, 'SELL' AS SIDE FROM TRADES TR JOIN ORDERS O_SELL ON TR.SELL_ORDER_ID = O_SELL.ORDER_ID WHERE O_SELL.USER_ID = #{userId} ) U_TRADES JOIN TRADES T ON U_TRADES.TRADE_ID = T.TRADE_ID ORDER BY T.CREATED_AT DESC LIMIT #{limit} OFFSET #{offset}

SELECT SUM(CNT) FROM ( SELECT COUNT(*) AS CNT FROM TRADES T JOIN ORDERS O_BUY ON T.BUY_ORDER_ID = O_BUY.ORDER_ID WHERE O_BUY.USER_ID = #{userId}
UNION ALL
SELECT COUNT(*) AS CNT FROM TRADES T JOIN ORDERS O_SELL ON T.SELL_ORDER_ID = O_SELL.ORDER_ID WHERE O_SELL.USER_ID = #{userId} ) TOTALS
